124	fn parseArgs(alloc: std.mem.Allocator, init_args: std.process.Args) Flags {
125	    var flags = Flags{ .remaining = .empty };
126	    var args = std.process.Args.Iterator.init(init_args);
127	    _ = args.next();
128	
129	    while (args.next()) |arg| {
130	        if (arg.len < 2 or arg[0] != '-') {
131	            flags.remaining.append(alloc, arg) catch {};
132	            while (args.next()) |rest| {
133	                flags.remaining.append(alloc, rest) catch {};
134	            }
135	            break;
136	        }
137	        for (arg[1..]) |c| {
138	            switch (c) {
139	                '2' => flags.force_256 = true,
140	                'C' => flags.control_mode = true,
141	                'D' => flags.no_daemon = true,
142	                'u' => flags.utf8_flag = true,
143	                'v' => flags.verbose +|= 1,
144	                'V' => flags.print_version = true,
145	                'h' => flags.print_help = true,
146	                'c' => {
147	                    flags.shell_command = args.next();
148	                    break;
149	                },
150	                'f' => {
151	                    flags.config_file = args.next();
152	                    break;
153	                },
154	                'L' => {
155	                    flags.socket_name = args.next();
156	                    break;
157	                },
158	                'S' => {
159	                    flags.socket_path = args.next();
160	                    break;
161	                },
162	                else => {},
163	            }
164	        }
165	    }
166	    return flags;
167	}
