169	fn resolveSocketPath(alloc: std.mem.Allocator, flags: *const Flags) ![]u8 {
170	    if (flags.socket_path) |path| {
171	        return try alloc.dupe(u8, path);
172	    }
173	    if (getenv("AGENTMUX_SOCKET_PATH")) |path| {
174	        return try alloc.dupe(u8, path);
175	    }
176	
177	    const socket_dir = try platform.core.defaultSocketDir(alloc);
178	    defer alloc.free(socket_dir);
179	    const socket_name = if (flags.socket_name) |sn|
180	        sn
181	    else if (getenv("AGENTMUX_SOCKET_NAME")) |sn|
182	        sn
183	    else
184	        default_socket_name;
185	
186	    return try std.fmt.allocPrint(alloc, "{s}/agentmux-{d}/{s}", .{
187	        socket_dir,
188	        std.c.getuid(),
189	        socket_name,
190	    });
191	}
