197	fn runServer(alloc: std.mem.Allocator, socket_path: []const u8, daemonize_server: bool, config_file: ?[:0]const u8) !void {
198	    if (daemonize_server) {
199	        try signals.daemonize();
200	    }
201	    signals.SignalHandler.install();
202	    var server = try server_mod.Server.init(alloc, socket_path);
203	    defer server.deinit();
204	    if (config_file) |cf| server.config_file = cf;
205	    try server.listen();
206	    server.loadDefaultConfig();
207	    try server.run();
208	}
