210	fn waitForServer(alloc: std.mem.Allocator, socket_path: []const u8) !void {
211	    var attempt: usize = 0;
212	    while (attempt < 100) : (attempt += 1) {
213	        var probe = client_mod.Client.init(alloc, socket_path);
214	        if (probe.connect()) {
215	            probe.disconnect();
216	            return;
217	        } else |_| {
218	            var delay = std.c.timespec{
219	                .sec = 0,
220	                .nsec = 50 * std.time.ns_per_ms,
221	            };
222	            _ = std.c.nanosleep(&delay, null);
223	        }
224	    }
225	    return error.ServerStartTimeout;
226	}
