228	fn autostartServer(alloc: std.mem.Allocator, socket_path: []const u8, config_file: ?[:0]const u8) !void {
229	    const pid = std.c.fork();
230	    if (pid < 0) return error.ForkFailed;
231	    if (pid == 0) {
232	        detachStdio();
233	        runServer(std.heap.c_allocator, socket_path, false, config_file) catch {};
234	        std.c.exit(0);
235	    }
236	    try waitForServer(alloc, socket_path);
237	}
