239	fn detachStdio() void {
240	    _ = std.c.setsid();
241	    _ = std.c.close(0);
242	    _ = std.c.close(1);
243	    _ = std.c.close(2);
244	
245	    const devnull: [*:0]const u8 = "/dev/null";
246	    const fd = std.c.open(devnull, .{ .ACCMODE = .RDWR }, @as(std.c.mode_t, 0));
247	    if (fd < 0) return;
248	    _ = std.c.dup2(fd, 0);
249	    _ = std.c.dup2(fd, 1);
250	    _ = std.c.dup2(fd, 2);
251	    if (fd > 2) _ = std.c.close(fd);
252	}
