254	fn runCommandMode(alloc: std.mem.Allocator, flags: *const Flags, socket_path: []const u8) !void {
255	    var client = client_mod.Client.init(alloc, socket_path);
256	    client.connect() catch |err| switch (err) {
257	        error.ConnectFailed => {
258	            try autostartServer(alloc, socket_path, flags.config_file);
259	            try client.connect();
260	        },
261	        else => return err,
262	    };
263	    defer client.disconnect();
264	
265	    var cols: u16 = 80;
266	    var rows: u16 = 24;
267	    if (client_terminal.getTerminalSize(0)) |ts| {
268	        cols = ts.cols;
269	        rows = ts.rows;
