480	fn appendPromptBytes(state: *PromptState, bytes: []const u8) void {
481	    const remaining = state.buffer.len - state.len;
482	    const copy_len = @min(remaining, bytes.len);
483	    if (copy_len == 0) return;
484	    @memcpy(state.buffer[state.len .. state.len + copy_len], bytes[0..copy_len]);
485	    state.len += copy_len;
486	}
