513	fn handlePromptKey(ctx: *Context, pane: *Pane, key_arg: []const u8) CmdError!bool {
514	    var prompt_state = &(pane.prompt_state orelse return false);
515	
516	    if (std.mem.eql(u8, key_arg, "Enter")) {
517	        try executePromptBuffer(ctx, pane);
518	        return true;
519	    }
520	    if (std.mem.eql(u8, key_arg, "Escape")) {
521	        pane.prompt_state = null;
522	        return true;
523	    }
524	    if (std.mem.eql(u8, key_arg, "BSpace")) {
525	        if (prompt_state.len > 0) prompt_state.len -= 1;
526	        return true;
527	    }
528	    if (std.mem.eql(u8, key_arg, "Space")) {
529	        appendPromptBytes(prompt_state, " ");
530	        return true;
531	    }
532	    if (std.mem.eql(u8, key_arg, "Tab")) {
533	        appendPromptBytes(prompt_state, "\t");
534	        return true;
535	    }
