541	fn addChooseTreeEntry(state: *ChooseTreeState, label: []const u8, depth: u8, has_children: bool, session: *Session, window: ?*Window, pane: ?*Pane) CmdError!void {
542	    const owned_label = state.allocator.dupe(u8, label) catch return CmdError.OutOfMemory;
543	    errdefer state.allocator.free(owned_label);
544	    state.labels.append(state.allocator, owned_label) catch return CmdError.OutOfMemory;
