const std = @import("std");

/// Key binding action.
pub const Action = union(enum) {
    /// Run a tmux command string.
    command: []const u8,
    /// No-op (unbound).
    none,
};

/// A single key binding.
pub const Binding = struct {
    key: u21,
    modifiers: Modifiers,
    action: Action,
};

pub const Modifiers = packed struct(u8) {
    ctrl: bool = false,
    meta: bool = false,
    shift: bool = false,
    _padding: u5 = 0,

    pub const none: Modifiers = .{};
};

/// A key table (e.g., "prefix", "root", "copy-mode-vi").
pub const KeyTable = struct {
    name: []const u8,
    bindings: std.ArrayListAligned(Binding, null),
    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator, name: []const u8) KeyTable {
        return .{
            .name = name,
            .bindings = .empty,
            .allocator = alloc,
        };
    }

    pub fn deinit(self: *KeyTable) void {
        for (self.bindings.items) |*b| {
            switch (b.action) {
                .command => |cmd| self.allocator.free(cmd),
                .none => {},
            }
        }
        self.bindings.deinit(self.allocator);
    }

    /// Bind a key to a command.
    pub fn bind(self: *KeyTable, key: u21, mods: Modifiers, command: []const u8) !void {
        // Remove existing binding for this key
        self.unbind(key, mods);

        const owned_cmd = try self.allocator.dupe(u8, command);
        try self.bindings.append(self.allocator, .{
            .key = key,
            .modifiers = mods,
            .action = .{ .command = owned_cmd },
        });
    }

    /// Unbind a key.
    pub fn unbind(self: *KeyTable, key: u21, mods: Modifiers) void {
        var i: usize = 0;
        while (i < self.bindings.items.len) {
            const b = &self.bindings.items[i];
            if (b.key == key and @as(u8, @bitCast(b.modifiers)) == @as(u8, @bitCast(mods))) {
                switch (b.action) {
                    .command => |cmd| self.allocator.free(cmd),
                    .none => {},
                }
                _ = self.bindings.orderedRemove(i);
            } else {
                i += 1;
            }
        }
    }

    /// Look up a binding.
    pub fn lookup(self: *const KeyTable, key: u21, mods: Modifiers) ?Action {
        for (self.bindings.items) |b| {
            if (b.key == key and @as(u8, @bitCast(b.modifiers)) == @as(u8, @bitCast(mods))) {
                return b.action;
            }
        }
        return null;
    }
};

/// Key binding manager with multiple tables.
pub const BindingManager = struct {
    tables: std.StringHashMap(KeyTable),
    prefix_key: u21,
    prefix_mods: Modifiers,
    in_prefix: bool,
    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator) BindingManager {
        return .{
            .tables = std.StringHashMap(KeyTable).init(alloc),
            .prefix_key = 'b', // C-b by default
            .prefix_mods = .{ .ctrl = true },
            .in_prefix = false,
            .allocator = alloc,
        };
    }

    pub fn deinit(self: *BindingManager) void {
        var iter = self.tables.iterator();
        while (iter.next()) |entry| {
            entry.value_ptr.deinit();
            self.allocator.free(entry.key_ptr.*);
        }
        self.tables.deinit();
    }

    /// Get or create a key table.
    pub fn getOrCreateTable(self: *BindingManager, name: []const u8) !*KeyTable {
        if (self.tables.getPtr(name)) |table| return table;

        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);

        try self.tables.put(owned_name, KeyTable.init(self.allocator, owned_name));
        return self.tables.getPtr(owned_name).?;
    }

    /// Process a key event. Returns the command to execute, if any.
    pub fn processKey(self: *BindingManager, key: u21, mods: Modifiers) ?[]const u8 {
        if (!self.in_prefix) {
            // Check root table first
            if (self.tables.get("root")) |root| {
                if (root.lookup(key, mods)) |action| {
                    switch (action) {
                        .command => |cmd| return cmd,
                        .none => {},
                    }
                }
            }

            // Check if this is the prefix key
            if (key == self.prefix_key and @as(u8, @bitCast(mods)) == @as(u8, @bitCast(self.prefix_mods))) {
                self.in_prefix = true;
                return null;
            }

            return null;
        }

        // In prefix mode: look up in prefix table
        self.in_prefix = false;

        if (self.tables.get("prefix")) |prefix| {
            if (prefix.lookup(key, mods)) |action| {
                switch (action) {
                    .command => |cmd| return cmd,
                    .none => {},
                }
            }
        }

        return null;
    }

    /// Set up default key bindings (matching tmux defaults).
    pub fn setupDefaults(self: *BindingManager) !void {
        const prefix = try self.getOrCreateTable("prefix");

        // Window management
        try prefix.bind('c', .{}, "new-window");
        try prefix.bind('n', .{}, "next-window");
        try prefix.bind('p', .{}, "previous-window");
        try prefix.bind('l', .{}, "last-window");
        try prefix.bind('w', .{}, "choose-tree -w");
        try prefix.bind('&', .{}, "kill-window");

        // Pane management
        try prefix.bind('%', .{}, "split-window -h");
        try prefix.bind('"', .{}, "split-window -v");
        try prefix.bind('o', .{}, "select-pane -t :.+");
        try prefix.bind('x', .{}, "kill-pane");
        try prefix.bind('z', .{}, "resize-pane -Z");
        try prefix.bind('{', .{}, "swap-pane -U");
        try prefix.bind('}', .{}, "swap-pane -D");

        // Session management
        try prefix.bind('d', .{}, "detach-client");
        try prefix.bind('s', .{}, "choose-tree -s");
        try prefix.bind('$', .{}, "rename-session");

        // Copy mode
        try prefix.bind('[', .{}, "copy-mode");
        try prefix.bind(']', .{}, "paste-buffer");

        // Misc
        try prefix.bind(':', .{}, "command-prompt");
        try prefix.bind('?', .{}, "list-keys");
        try prefix.bind('t', .{}, "clock-mode");

        // Number keys for window selection
        var digit: u21 = '0';
        while (digit <= '9') : (digit += 1) {
            var buf: [32]u8 = undefined;
            const cmd = std.fmt.bufPrint(&buf, "select-window -t :{d}", .{digit - '0'}) catch continue;
            try prefix.bind(digit, .{}, cmd);
        }
    }
};

test "key table bind and lookup" {
    var table = KeyTable.init(std.testing.allocator, "test");
    defer table.deinit();

    try table.bind('c', .{}, "new-window");
    const action = table.lookup('c', .{}).?;
    switch (action) {
        .command => |cmd| try std.testing.expectEqualStrings("new-window", cmd),
        .none => return error.UnexpectedNone,
    }

    try std.testing.expect(table.lookup('x', .{}) == null);
}

test "binding manager prefix" {
    var mgr = BindingManager.init(std.testing.allocator);
    defer mgr.deinit();

    const prefix = try mgr.getOrCreateTable("prefix");
    try prefix.bind('c', .{}, "new-window");

    // Not in prefix: C-b should activate prefix
    const r1 = mgr.processKey('b', .{ .ctrl = true });
    try std.testing.expect(r1 == null);
    try std.testing.expect(mgr.in_prefix);

    // In prefix: 'c' should return command
    const r2 = mgr.processKey('c', .{});
    try std.testing.expect(r2 != null);
    try std.testing.expectEqualStrings("new-window", r2.?);
    try std.testing.expect(!mgr.in_prefix);
}

test "default deferred bindings produce explicit messages" {
    var mgr = BindingManager.init(std.testing.allocator);
    defer mgr.deinit();
    try mgr.setupDefaults();

    _ = mgr.processKey('b', .{ .ctrl = true });
    const choose_tree = mgr.processKey('w', .{});
    try std.testing.expect(choose_tree != null);
    try std.testing.expectEqualStrings("choose-tree -w", choose_tree.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const list_keys = mgr.processKey('?', .{});
    try std.testing.expect(list_keys != null);
    try std.testing.expectEqualStrings("list-keys", list_keys.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const zoom = mgr.processKey('z', .{});
    try std.testing.expect(zoom != null);
    try std.testing.expectEqualStrings("resize-pane -Z", zoom.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const paste = mgr.processKey(']', .{});
    try std.testing.expect(paste != null);
    try std.testing.expectEqualStrings("paste-buffer", paste.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const copy = mgr.processKey('[', .{});
    try std.testing.expect(copy != null);
    try std.testing.expectEqualStrings("copy-mode", copy.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const prompt = mgr.processKey(':', .{});
    try std.testing.expect(prompt != null);
    try std.testing.expectEqualStrings("command-prompt", prompt.?);

    _ = mgr.processKey('b', .{ .ctrl = true });
    const clock = mgr.processKey('t', .{});
    try std.testing.expect(clock != null);
    try std.testing.expectEqualStrings("clock-mode", clock.?);
}

const std = @import("std");
const Window = @import("window.zig").Window;
const Pane = @import("window.zig").Pane;
const Environ = @import("core/environ.zig").Environ;
const Style = @import("status/style.zig").Style;

/// An agentmux session. Contains windows and tracks attached clients.
pub const Session = struct {
    id: u32,
    name: []const u8,

    windows: std.ArrayListAligned(*Window, null),
    active_window: ?*Window,
    last_window: ?*Window,

    attached: u32,
    flags: Flags,

    options: Options,
    environ: Environ,

    allocator: std.mem.Allocator,

    pub const Flags = packed struct(u8) {
        alerted: bool = false,
        _padding: u7 = 0,
    };

    pub const Options = struct {
        base_index: u32 = 0,
        default_shell: [:0]u8,
        status: bool = true,
        mouse: bool = false,
        prefix_key: u21 = 0x02, // C-b
        prefix_string: []u8,
        status_style: Style = .{
            .fg = .green,
            .bg = .black,
            .attrs = .{},
        },
        status_left: []u8,
        status_right: []u8,
        visual_activity: bool = false,
    };

    var next_id: u32 = 0;

    pub fn init(alloc: std.mem.Allocator, name: []const u8) !*Session {
        const s = try alloc.create(Session);
        errdefer alloc.destroy(s);

        const owned_name = try alloc.dupe(u8, name);
        errdefer alloc.free(owned_name);
        const default_shell = try alloc.dupeZ(u8, "/bin/sh");
        errdefer alloc.free(default_shell);
        const prefix_string = try alloc.dupe(u8, "C-b");
        errdefer alloc.free(prefix_string);
        const status_left = try alloc.dupe(u8, "[#S]");
        errdefer alloc.free(status_left);
        const status_right = try alloc.dupe(u8, "#H");
        errdefer alloc.free(status_right);

        s.* = .{
            .id = next_id,
            .name = owned_name,
            .windows = .empty,
            .active_window = null,
            .last_window = null,
            .attached = 0,
            .flags = .{},
            .options = .{
                .default_shell = default_shell,
                .prefix_string = prefix_string,
                .status_left = status_left,
                .status_right = status_right,
            },
            .environ = Environ.init(alloc),
            .allocator = alloc,
        };
        next_id += 1;
        return s;
    }

    pub fn deinit(self: *Session) void {
        for (self.windows.items) |w| {
            w.deinit();
        }
        self.windows.deinit(self.allocator);
        self.environ.deinit();
        self.allocator.free(self.options.default_shell);
        self.allocator.free(self.options.prefix_string);
        self.allocator.free(self.options.status_left);
        self.allocator.free(self.options.status_right);
        self.allocator.free(self.name);
        self.allocator.destroy(self);
    }

    /// Add a window to the session.
    pub fn addWindow(self: *Session, window: *Window) !void {
        try self.windows.append(self.allocator, window);
        if (self.active_window == null) {
            self.active_window = window;
        }
    }

    /// Find a window by index.
    pub fn findWindow(self: *const Session, index: u32) ?*Window {
        for (self.windows.items) |w| {
            if (w.id == index) return w;
        }
        return null;
    }

    /// Find a window by its displayed number (base-index-adjusted position).
    pub fn findWindowByNumber(self: *const Session, number: u32) ?*Window {
        if (number < self.options.base_index) return null;
        const offset = number - self.options.base_index;
        if (offset >= self.windows.items.len) return null;
        return self.windows.items[offset];
    }

    /// Get the number of windows.
    pub fn windowCount(self: *const Session) usize {
        return self.windows.items.len;
    }

    /// Select the next window.
    pub fn nextWindow(self: *Session) void {
        if (self.windows.items.len == 0) return;
        if (self.active_window) |active| {
            for (self.windows.items, 0..) |w, i| {
                if (w == active) {
                    const next_idx = (i + 1) % self.windows.items.len;
                    self.active_window = self.windows.items[next_idx];
                    return;
                }
            }
        }
        self.active_window = self.windows.items[0];
    }

    /// Select the previous window.
    pub fn prevWindow(self: *Session) void {
        if (self.windows.items.len == 0) return;
        if (self.active_window) |active| {
            for (self.windows.items, 0..) |w, i| {
                if (w == active) {
                    const prev_idx = if (i == 0) self.windows.items.len - 1 else i - 1;
                    self.active_window = self.windows.items[prev_idx];
                    return;
                }
            }
        }
    }

    /// Select a specific window, tracking the previous one.
    pub fn selectWindow(self: *Session, window: *Window) void {
        if (self.active_window) |current| {
            if (current != window) {
                self.last_window = current;
            }
        }
        self.active_window = window;
    }

    /// Switch to the last active window.
    pub fn lastWindow(self: *Session) bool {
        if (self.last_window) |last| {
            // Verify it's still in the window list
            for (self.windows.items) |w| {
                if (w == last) {
                    self.selectWindow(last);
                    return true;
                }
            }
            self.last_window = null;
        }
        return false;
    }

    /// Remove and destroy a window. Returns true if the session has no windows left.
    pub fn removeWindow(self: *Session, window: *Window) bool {
        // If this was the last_window, clear it
        if (self.last_window == window) {
            self.last_window = null;
        }

        for (self.windows.items, 0..) |w, i| {
            if (w == window) {
                _ = self.windows.orderedRemove(i);
                break;
            }
        }

        // If active window was removed, select another
        if (self.active_window == window) {
            self.active_window = if (self.windows.items.len > 0) self.windows.items[0] else null;
        }

        window.deinit();
        return self.windows.items.len == 0;
    }

    /// Rename the session.
    pub fn rename(self: *Session, new_name: []const u8) !void {
        const owned = try self.allocator.dupe(u8, new_name);
        self.allocator.free(self.name);
        self.name = owned;
    }

    pub fn setDefaultShell(self: *Session, shell: []const u8) !void {
        const owned = try self.allocator.dupeZ(u8, shell);
        self.allocator.free(self.options.default_shell);
        self.options.default_shell = owned;
    }

    pub fn setPrefix(self: *Session, prefix_string: []const u8, prefix_key: u21) !void {
        const owned = try self.allocator.dupe(u8, prefix_string);
        self.allocator.free(self.options.prefix_string);
        self.options.prefix_string = owned;
        self.options.prefix_key = prefix_key;
    }

    pub fn setStatusLeft(self: *Session, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.status_left);
        self.options.status_left = owned;
    }

    pub fn setStatusRight(self: *Session, value: []const u8) !void {
        const owned = try self.allocator.dupe(u8, value);
        self.allocator.free(self.options.status_right);
        self.options.status_right = owned;
    }
};

test "findWindowByNumber uses base index" {
    const alloc = std.testing.allocator;
    var session = try Session.init(alloc, "demo");
    defer session.deinit();
    session.options.base_index = 1;

    var w1 = try Window.init(alloc, "one", 80, 24);
    var w2 = try Window.init(alloc, "two", 80, 24);

    const p1 = try Pane.init(alloc, 80, 24);
    const p2 = try Pane.init(alloc, 80, 24);
    try w1.addPane(p1);
    try w2.addPane(p2);
    try session.addWindow(w1);
    try session.addWindow(w2);

    try std.testing.expect(session.findWindowByNumber(0) == null);
    try std.testing.expect(session.findWindowByNumber(1) == w1);
    try std.testing.expect(session.findWindowByNumber(2) == w2);
}

