        const buffer = ctx.server.paste_stack.get(index) orelse continue;
        if (buffer.name) |name| {
            try writeOutput(ctx, "{d}: {s} ({d} bytes)\n", .{ index, name, buffer.data.len });
        } else {
            try writeOutput(ctx, "{d}: buffer{d} ({d} bytes)\n", .{ index, index, buffer.data.len });
