        try self.register(.{ .name = "break-pane", .alias = "breakp", .min_args = 0, .max_args = 10, .usage = "break-pane (breakp) [-abdP] [-F format] [-n window-name] [-s src-pane] [-t dst-window]", .handler = cmdNotImplemented });
